line(P1, P2) ->
    X1 = element(1, P1),
    Y1 = element(2, P1),
    X2 = element(1, P2),
    Y2 = element(2, P2),
    Slope = case X2 - X1 of
        0 -> infinity;
        _ -> (Y2 - Y1) / (X2 - X1)
    end,
    #{slope => Slope, points => {P1, P2}}.
